import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.Pywvta2k.js";const y=JSON.parse('{"title":"针灸常用腧穴速查","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/06-跨病证索引/10-针灸常用腧穴.md","filePath":"tcm-data/06-跨病证索引/10-针灸常用腧穴.md","lastUpdated":1781084559000}'),d={name:"tcm-data/06-跨病证索引/10-针灸常用腧穴.md"};function n(s,t,g,i,o,x){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="针灸常用腧穴速查" tabindex="-1">针灸常用腧穴速查 <a class="header-anchor" href="#针灸常用腧穴速查" aria-label="Permalink to &quot;针灸常用腧穴速查&quot;">​</a></h1><blockquote><p>常用穴位的定位、功效、主治 可作为自我保健参考</p></blockquote><hr><h2 id="一、常用保健要穴" tabindex="-1">一、常用保健要穴 <a class="header-anchor" href="#一、常用保健要穴" aria-label="Permalink to &quot;一、常用保健要穴&quot;">​</a></h2><h3 id="足三里-胃经-——-第一保健要穴" tabindex="-1">足三里（胃经）—— 第一保健要穴 <a class="header-anchor" href="#足三里-胃经-——-第一保健要穴" aria-label="Permalink to &quot;足三里（胃经）—— 第一保健要穴&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>定位</strong></td><td style="text-align:left;">小腿外侧，膝眼下3寸（四横指）</td></tr><tr><td style="text-align:left;"><strong>功效</strong></td><td style="text-align:left;">健脾和胃，益气养血，强身健体</td></tr><tr><td style="text-align:left;"><strong>适应</strong></td><td style="text-align:left;">胃肠虚弱、疲劳、免疫力低下</td></tr><tr><td style="text-align:left;"><strong>手法</strong></td><td style="text-align:left;">按揉或艾灸10-15分钟</td></tr><tr><td style="text-align:left;"><strong>不同类型患者</strong></td><td style="text-align:left;">✅ 两人都适合（中气虚）</td></tr></tbody></table><h3 id="关元-任脉-——-元气之根" tabindex="-1">关元（任脉）—— 元气之根 <a class="header-anchor" href="#关元-任脉-——-元气之根" aria-label="Permalink to &quot;关元（任脉）—— 元气之根&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>定位</strong></td><td style="text-align:left;">肚脐下3寸（四横指）</td></tr><tr><td style="text-align:left;"><strong>功效</strong></td><td style="text-align:left;">补肾固元，温阳散寒</td></tr><tr><td style="text-align:left;"><strong>适应</strong></td><td style="text-align:left;">肾虚、腰凉、遗精、月经不调</td></tr><tr><td style="text-align:left;"><strong>手法</strong></td><td style="text-align:left;">艾灸15-20分钟（最适合）</td></tr><tr><td style="text-align:left;"><strong>不同类型患者</strong></td><td style="text-align:left;">✅ 患者（男）腰凉+患者（女）小腹凉→都适合灸</td></tr></tbody></table><h3 id="命门-督脉-——-生命之门" tabindex="-1">命门（督脉）—— 生命之门 <a class="header-anchor" href="#命门-督脉-——-生命之门" aria-label="Permalink to &quot;命门（督脉）—— 生命之门&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>定位</strong></td><td style="text-align:left;">腰部后正中线，第2腰椎棘突下（肚脐正后方）</td></tr><tr><td style="text-align:left;"><strong>功效</strong></td><td style="text-align:left;">温肾壮阳，强腰脊</td></tr><tr><td style="text-align:left;"><strong>适应</strong></td><td style="text-align:left;">腰凉、腰痛、阳痿、泄泻</td></tr><tr><td style="text-align:left;"><strong>手法</strong></td><td style="text-align:left;">艾灸15-20分钟</td></tr><tr><td style="text-align:left;"><strong>患者（男）</strong></td><td style="text-align:left;">⭐ <strong>特别适合</strong>（腰凉核心穴）</td></tr></tbody></table><h3 id="气海-任脉" tabindex="-1">气海（任脉） <a class="header-anchor" href="#气海-任脉" aria-label="Permalink to &quot;气海（任脉）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>定位</strong></td><td style="text-align:left;">肚脐下1.5寸（关元与肚脐正中）</td></tr><tr><td style="text-align:left;"><strong>功效</strong></td><td style="text-align:left;">补气培元</td></tr><tr><td style="text-align:left;"><strong>适应</strong></td><td style="text-align:left;">气虚乏力、中气下陷</td></tr><tr><td style="text-align:left;"><strong>手法</strong></td><td style="text-align:left;">艾灸10-15分钟</td></tr></tbody></table><h3 id="三阴交-脾经" tabindex="-1">三阴交（脾经） <a class="header-anchor" href="#三阴交-脾经" aria-label="Permalink to &quot;三阴交（脾经）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>定位</strong></td><td style="text-align:left;">小腿内侧，足内踝尖上3寸</td></tr><tr><td style="text-align:left;"><strong>功效</strong></td><td style="text-align:left;">调肝脾肾三经</td></tr><tr><td style="text-align:left;"><strong>适应</strong></td><td style="text-align:left;">妇科诸疾（月经不调、带下）</td></tr><tr><td style="text-align:left;"><strong>患者（女）</strong></td><td style="text-align:left;">⭐ <strong>特别适合</strong>（妇科要穴）</td></tr></tbody></table><hr><h2 id="二、患者症状对应穴位" tabindex="-1">二、患者症状对应穴位 <a class="header-anchor" href="#二、患者症状对应穴位" aria-label="Permalink to &quot;二、患者症状对应穴位&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">症状</th><th style="text-align:left;">推荐穴位</th><th style="text-align:left;">手法</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>腰腹部凉</strong></td><td style="text-align:left;">关元+命门+肾俞</td><td style="text-align:left;">艾灸10-15分钟</td></tr><tr><td style="text-align:left;"><strong>阴囊潮湿</strong></td><td style="text-align:left;">阴陵泉+三阴交+太冲</td><td style="text-align:left;">按揉</td></tr><tr><td style="text-align:left;"><strong>膝盖痛</strong></td><td style="text-align:left;">膝眼+阳陵泉+足三里</td><td style="text-align:left;">艾灸或按揉</td></tr><tr><td style="text-align:left;"><strong>脚后跟裂</strong></td><td style="text-align:left;">太溪+照海+涌泉</td><td style="text-align:left;">按揉+泡脚</td></tr><tr><td style="text-align:left;"><strong>血压高</strong></td><td style="text-align:left;">太冲+曲池+足三里</td><td style="text-align:left;">按压</td></tr><tr><td style="text-align:left;"><strong>疲劳</strong></td><td style="text-align:left;">足三里+气海+关元</td><td style="text-align:left;">艾灸</td></tr><tr><td style="text-align:left;"><strong>目干涩</strong></td><td style="text-align:left;">太冲+肝俞+睛明</td><td style="text-align:left;">按压</td></tr></tbody></table><h3 id="患者-男-自我保健灸法-推荐" tabindex="-1">患者（男）自我保健灸法（推荐） <a class="header-anchor" href="#患者-男-自我保健灸法-推荐" aria-label="Permalink to &quot;患者（男）自我保健灸法（推荐）&quot;">​</a></h3><p><strong>每日艾灸：关元+足三里+命门</strong></p><ul><li>早晨灸足三里+命门（升阳气）</li><li>晚上灸关元（引火归原）</li><li>每穴10-15分钟，温热为度</li></ul><hr><h2 id="三、患者-女-症状对应穴位" tabindex="-1">三、患者（女）症状对应穴位 <a class="header-anchor" href="#三、患者-女-症状对应穴位" aria-label="Permalink to &quot;三、患者（女）症状对应穴位&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">症状</th><th style="text-align:left;">推荐穴位</th><th style="text-align:left;">手法</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>月经先期</strong></td><td style="text-align:left;">三阴交+血海+关元</td><td style="text-align:left;">艾灸关元，按揉三阴交</td></tr><tr><td style="text-align:left;"><strong>白带多</strong></td><td style="text-align:left;">带脉+阴陵泉+三阴交</td><td style="text-align:left;">艾灸</td></tr><tr><td style="text-align:left;"><strong>失眠</strong></td><td style="text-align:left;">神门+内关+三阴交</td><td style="text-align:left;">按压（睡前）</td></tr><tr><td style="text-align:left;"><strong>烦躁</strong></td><td style="text-align:left;">太冲+行间+膻中</td><td style="text-align:left;">按压</td></tr><tr><td style="text-align:left;"><strong>疲劳</strong></td><td style="text-align:left;">足三里+气海</td><td style="text-align:left;">艾灸</td></tr></tbody></table><h3 id="患者-女-自我保健" tabindex="-1">患者（女）自我保健 <a class="header-anchor" href="#患者-女-自我保健" aria-label="Permalink to &quot;患者（女）自我保健&quot;">​</a></h3><p><strong>每日：</strong></p><ul><li>早晨按揉足三里+三阴交（各3分钟）</li><li>晚上按揉神门+太冲（各2分钟）</li><li>经前艾灸关元（10分钟）</li></ul><hr><h2 id="四、禁忌与注意事项" tabindex="-1">四、禁忌与注意事项 <a class="header-anchor" href="#四、禁忌与注意事项" aria-label="Permalink to &quot;四、禁忌与注意事项&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">禁忌</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>过饥过饱</strong></td><td style="text-align:left;">饭前30分钟、饭后1小时内不宜针灸</td></tr><tr><td style="text-align:left;"><strong>大汗后</strong></td><td style="text-align:left;">不宜立即针灸</td></tr><tr><td style="text-align:left;"><strong>孕妇</strong></td><td style="text-align:left;">合谷、三阴交、肩井等穴禁用</td></tr><tr><td style="text-align:left;"><strong>出血倾向</strong></td><td style="text-align:left;">不宜针灸</td></tr><tr><td style="text-align:left;"><strong>皮肤感染</strong></td><td style="text-align:left;">局部不宜针灸</td></tr></tbody></table><h3 id="艾灸注意事项" tabindex="-1">艾灸注意事项 <a class="header-anchor" href="#艾灸注意事项" aria-label="Permalink to &quot;艾灸注意事项&quot;">​</a></h3><ol><li>艾灸后<strong>避风寒</strong>（灸后毛孔张开）</li><li>艾灸后喝<strong>温开水</strong>（不喝凉水）</li><li>艾灸时间以<strong>温热感为度</strong>，不要烫伤</li><li>阴虚火旺者（如患者（女）有潮热盗汗）<strong>不宜过量艾灸</strong></li></ol><hr><p><em>本索引为精简框架版。可在后续扩展至十四经循行、特定穴（原穴、络穴、郄穴、募穴、背俞穴）专题、子午流注等。</em></p>',33)])])}const h=e(d,[["render",n]]);export{y as __pageData,h as default};
